interface CartItem {
  id: string;
  name: string;
  price: number;
}

interface ShippingOption {
  id: string;
  name: string;
  price: number;
  estimated_days: number;
  carrier: string;
}

interface FormData {
  email: string;
  cardNumber: string;
  expiry: string;
  cvv: string;
  promoCode: string;
}

interface ValidationErrors {
  [key: string]: string;
}

const CheckoutForm: React.FC<{ items: CartItem[]; shippingOptions: ShippingOption[] }> = ({ items, shippingOptions }) => {
  <aap:target id="form-state">
  const [formData, setFormData] = React.useState<FormData>({ email: '', cardNumber: '', expiry: '', cvv: '', promoCode: '' });
  const [errors, setErrors] = React.useState<ValidationErrors>({});
  const [loading, setLoading] = React.useState(false);
  const [discount, setDiscount] = React.useState(0);
  </aap:target>

  const validate = (): boolean => {
    const newErrors: ValidationErrors = {};
    if (!/^\S+@\S+\.\S+$/.test(formData.email)) newErrors.email = "Invalid email";
    // Luhn check logic here
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const applyPromo = () => {
    if (formData.promoCode === 'SAVE10') setDiscount(10);
    else alert('Invalid promo code');
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;
    setLoading(true);
    // Submit logic
    setLoading(false);
  };

  const subtotal = items.reduce((sum, item) => sum + item.price, 0);
  const total = Math.max(0, subtotal - discount);

  return (
    <div style={{ display: 'flex', gap: '2rem', padding: '2rem' }}>
      <form onSubmit={handleSubmit} style={{ flex: 2 }}>
        <aap:target id="form-fields">
          <input 
            type="email" 
            placeholder="Email" 
            onChange={(e) => setFormData({...formData, email: e.target.value})} 
          />
          {errors.email && <span style={{ color: 'red' }}>{errors.email}</span>}
          <div style={{ marginTop: '1rem' }}>
            <input 
              type="text" 
              placeholder="Promo Code" 
              value={formData.promoCode}
              onChange={(e) => setFormData({...formData, promoCode: e.target.value})}
            />
            <button type="button" onClick={applyPromo}>Apply</button>
          </div>
        </aap:target>
        <button type="submit" disabled={loading}>
          <aap:target id="submit-button-text">Place Order</aap:target>
        </button>
      </form>

      <aside style={{ flex: 1, border: '1px solid #ccc', padding: '1rem' }}>
        <h3>Order Summary</h3>
        <aap:target id="order-summary-list">
          {items.map(item => <div key={item.id}>{item.name}: ${item.price}</div>)}
        </aap:target>
        {discount > 0 && <div>Discount: -${discount}</div>}
        <div style={{ marginTop: '1rem', borderTop: '1px solid #000' }}>
          <strong>Total: </strong>
          <aap:target id="total-price">${total.toFixed(2)}</aap:target>
        </div>
      </aside>
    </div>
  );
};
